window.onload = init;
// Job array objects
var jobs = [];
var thisJob = [];
var error = document.getElementById('error')
var jobWrapper = document.getElementById("jobs_wrapper");
// Init function
function init() {
    // reading the url param query keywords
    const params = new URLSearchParams(window.location.search);

    const jobID = parseInt(params.get("job_id")); // Extract the job id 
    // read the json data file
    const endpoint = './assets/json/data.json';
    // Create httprequest object
    var xhr = new XMLHttpRequest()
    // open the connection;
    xhr.open('GET', endpoint, true);
    // response type of JSON data
    xhr.responseType = 'json';
    // onload with the open connection
    // xhr.onload = function () {
    xhr.onload = function () {
        //
        // Check the xhr response status
        if (xhr.status === 200) {
            const jobs = xhr.response;
            thisJob = jobs.jobs.filter(job => job.id === jobID)
            thisJob.forEach(job => {
                // Jobs cards
                jobWrapper.innerHTML += `
        <a href="job.html?job_id=${job.id}" style="color:inherit">
<div class="job_card">
<i class="fa-regular fa-star icon"></i>
              <div class="logo">
                <img src="./assets/img/company/${job.logo}" alt="" />
              </div>
                <div class="job_details">
                <h3 class="">${job.role}</h3>
                <h4 class="company">${job.company}</h4>
                <div class="location_type">
                  <span class="badge">${job.location}</span>
                  <span class="badge1">${job.type}</span>
                  <p class="description">${job.description}
                  </p>
                  <p class="ago">${job.posted}</p>
                </div>
              </div>
              </div>
              </a>
            `;

            });

        } else {
            error.innerHTML = "Connection Error. Try again later...."
            console.log("this is connect error")
        }
    };
    xhr.send(null); // Close the connect to NULL

}